// M004 - All 10 success criteria DOM checks
const results = {};

// 1. 7 cards with data-certeza
results.cr1_certeza_count = document.querySelectorAll('#periodo-nacional [data-certeza]').length;
results.cr1_pass = results.cr1_certeza_count === 7;

// 2. 7 card images
results.cr2_img_count = document.querySelectorAll('#periodo-nacional .card-image img').length;
results.cr2_pass = results.cr2_img_count === 7;

// 3. At least 2 certeza types
const certezaTypes = new Set();
document.querySelectorAll('#periodo-nacional [data-certeza]').forEach(el => certezaTypes.add(el.dataset.certeza));
results.cr3_certeza_types = [...certezaTypes];
results.cr3_pass = certezaTypes.size >= 2;

// 4. Alberdi arc - check for 1884, alberdi/legado mentions
const nationalText = document.querySelector('#periodo-nacional')?.textContent?.toLowerCase() || '';
results.cr4_has_1884 = nationalText.includes('1884');
results.cr4_has_alberdi = nationalText.includes('alberdi');
results.cr4_has_legado = nationalText.includes('legado') || nationalText.includes('legacy') || nationalText.includes('herencia');
results.cr4_pass = results.cr4_has_1884 && results.cr4_has_alberdi;

// 5. Cite elements >=7
results.cr5_cite_count = document.querySelectorAll('#periodo-nacional cite').length;
results.cr5_pass = results.cr5_cite_count >= 7;

// 6. Opinión cards have blockquote with attribution
const opinionCards = document.querySelectorAll('#periodo-nacional [data-certeza="opinión"], #periodo-nacional [data-certeza="opinion"]');
results.cr6_opinion_count = opinionCards.length;
let opinionHasBlockquote = true;
opinionCards.forEach(card => {
  const bq = card.querySelector('blockquote');
  const cite = card.querySelector('cite, blockquote cite, figcaption');
  if (!bq || !cite) opinionHasBlockquote = false;
});
results.cr6_has_blockquote = opinionHasBlockquote;
results.cr6_pass = opinionCards.length > 0 && opinionHasBlockquote;

// 7. Animated timeline present
results.cr7_timeline_exists = document.querySelector('.nacional-timeline') !== null;
results.cr7_marker_count = document.querySelectorAll('.nacional-timeline__marker').length;
results.cr7_pass = results.cr7_timeline_exists && results.cr7_marker_count === 7;

// 8. events-grid--certeza class
results.cr8_grid_class = document.querySelector('#periodo-nacional .events-grid--certeza') !== null;
results.cr8_pass = results.cr8_grid_class;

// 9. Reveal system integration for timeline
results.cr9_reveal_class = document.querySelector('.nacional-timeline')?.classList.contains('reveal') ?? false;
results.cr9_pass = results.cr9_reveal_class;

// 10. 0 img-error or img-fallback elements
results.cr10_errors = document.querySelectorAll('#periodo-nacional .img-error, #periodo-nacional .img-fallback').length;
results.cr10_pass = results.cr10_errors === 0;

// Summary
results.all_pass = Object.keys(results).filter(k => k.endsWith('_pass')).every(k => results[k]);
results.pass_count = Object.keys(results).filter(k => k.endsWith('_pass') && results[k]).length;
results.total_criteria = Object.keys(results).filter(k => k.endsWith('_pass')).length;

return results;

